private Path composeThemePath(String key) throws IOException {

        if (!key.matches("[A-Za-z0-9_-]+")) {
            throw new IOException("Invalid theme identifier");
        }

        Path folder = storagePath.resolve(key);

        return folder.resolve("theme.txt");
    }
